model_equation.equation:
\begin{aligned}
Y_{ij}^{\text{norm}} = \;& \beta_0 + \beta_1 GW_{ij} + \beta_2 GW_{ij}^2 + \beta_3 BMI_i + \beta_4 H_i \\
&+ \beta_5 (GW_{ij} \times BMI_i) \\
&+ u_i + v_i GW_{ij} + \epsilon_{ij}
\end{aligned}

model_selection.equation:
\begin{aligned}
M_0 &: \text{OLS: } Y = \beta_0 + \beta_1 GW + \beta_2 GW^2 + \beta_3 BMI + \beta_4 H + \epsilon \quad (\text{无随机效应})\\
M_1 &: \text{随机截距: } + u_i \\
M_2 &: \text{随机截距 + 随机斜率: } + u_i + v_i GW \\
M_3 &: \text{完整模型: } M_2 + \text{交互项 } GW \times BMI
\end{aligned}

stage.equation:
\textbf{给定观测数据后的后验预测:} \quad
\begin{aligned}
Y_* \mid \mathbf{Y}_i &\sim N(\mu_*, \Sigma_*) \\[4pt]
\mu_* &= m(GW_*) + k(GW_*, GW_i) [k(GW_i, GW_i) + \sigma_n^2 I]^{-1} (\mathbf{Y}_i - m(GW_i)) \\[4pt]
\Sigma_* &= k(GW_*, GW_*) - k(GW_*, GW_i) [k(GW_i, GW_i) + \sigma_n^2 I]^{-1} k(GW_i, GW_*)
\end{aligned}

constraints.equation:
\begin{aligned}
\text{边界单调性:} \quad & b_1 < b_2 < \cdots < b_{K-1} \\
\text{时点可行域:} \quad & 8 \leq t_1^{\text{opt}}, \ldots, t_K^{\text{opt}} \leq 24 \\
\text{覆盖率约束:} \quad & 1 - F_{\text{ail}}(t_g^{\text{opt}} \mid g) \geq q_{\min}, \quad \forall g=1,\ldots,K \\
\text{分位数水平:} \quad & \text{可选设定 } q_{\min} \in \{0.5, 0.7, 0.9, 0.95\} \text{ 作为灵敏度分析}
\end{aligned}

ga_encoding.description:
遗传算法的染色体编码方案：
\begin{itemize}
  \item 实数编码：染色体向量为 $\mathbf{c} = [b_1, \ldots, b_{K-1}, t_1^{\text{opt}}, \ldots, t_K^{\text{opt}}] \in \mathbb{R}^{2K-1}$
  \item 边界单调性约束通过编码时排序保证：对 $b_1,\ldots,b_{K-1}$ 做升序排列后再解码
  \item 适应度函数：$F(\mathbf{c}) = -\mathcal{R}(\mathbf{c})$（负风险，最大化）
\end{itemize}
